create table awh_main.awh_erhebungsbogen_2 (
    eb2_lfd_nr                number default to_number(sys_guid(), 'XXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXXX'),
    asy_lfd_nr                number not null enable,
    eb2_zweck_persdaten       varchar2(4000 byte),
    eb2_spezialgesetz_regel   varchar2(4000 byte),
    eb2_einwilligung          varchar2(4000 byte),
    eb2_kollektivvereinbarung varchar2(4000 byte),
    eb2_beschaeftigung        varchar2(4000 byte),
    eb2_vertragsanbahnung     varchar2(4000 byte),
    eb2_interessenabwaegung   varchar2(4000 byte),
    eb2_timestamp             timestamp(6) default sysdate not null enable,
    eb2_user                  varchar2(100 byte)
)
no inmemory;

alter table awh_main.awh_erhebungsbogen_2
    add constraint awh_erhebungsbogen_2_pk primary key ( eb2_lfd_nr )
        using index enable;


